pragma solidity 0.8.21;

// solhint-disable no-unused-import

import {PROXY_IMPL_SLOT} from "./constants.sol";

// solhint-enable no-unused-import

contract Proxy {
  // deployment

  constructor(address proxyImpl) {
    // solhint-disable-next-line no-inline-assembly
    assembly {
      sstore(PROXY_IMPL_SLOT, proxyImpl)
    }
  }

  // wildcard

  fallback() external payable {
    // solhint-disable-next-line no-inline-assembly
    assembly {
      let proxyImpl := sload(PROXY_IMPL_SLOT)

      calldatacopy(0, 0, calldatasize())

      let success := delegatecall(gas(), proxyImpl, 0, calldatasize(), 0, 0)

      returndatacopy(0, 0, returndatasize())

      if eq(success, 0) {
        revert(0, returndatasize())
      }

      return(0, returndatasize())
    }
  }
}
","keccak256":"0x7812510002afafa6dd012fae48fd8f110f9aee7d86f9f4db37841b7dd6772376","license":"NONE"},"contracts/common/proxy/ProxyFactory.sol":{"content":"// SPDX-License-Identifier: NONE
pragma solidity 0.8.21;

import {Proxy} from "./Proxy.sol";

abstract contract ProxyFactory {
  // internal setters

  function _createProxy(
    address proxyImpl,
    bytes32 salt
  ) internal returns (address result) {
    try new Proxy{salt: salt}(proxyImpl) returns (Proxy proxy) {
      result = address(proxy);
    } catch {
      result = address(0);
    }

    return result;
  }
}
